UPDATE `#__jem_config` SET `value` = JSON_INSERT(`value`, '$.actionlog_enabled', '0') WHERE `keyname` = 'globalattribs' AND JSON_EXTRACT(`value`, '$.actionlog_enabled') IS NULL;
UPDATE `#__jem_config` SET `value` = JSON_INSERT(`value`, '$.event_detail_image_layout', 'right', '$.event_detail_image_header_display', 'fill', '$.event_detail_image_header_max_height', '420') WHERE `keyname` = 'globalattribs' AND JSON_EXTRACT(`value`, '$.event_detail_image_layout') IS NULL;
UPDATE `#__jem_config` SET `value` = JSON_INSERT(`value`, '$.event_detail_image_header_display', 'fill', '$.event_detail_image_header_max_height', '420') WHERE `keyname` = 'globalattribs' AND JSON_EXTRACT(`value`, '$.event_detail_image_header_display') IS NULL;
UPDATE `#__jem_config` SET `value` = JSON_INSERT(`value`, '$.calendar_special_days_enabled', '1', '$.calendar_special_day_types', 'Weekend | #d1d5db | 0\nPublic holiday | #e5e7eb | 0') WHERE `keyname` = 'globalattribs';
UPDATE `#__jem_special_days` SET `title` = 'Saturday and Sunday', `description` = 'Regular weekend days' WHERE `title` = 'Weekend' AND `day_type` = 'Weekend' AND (`description` IS NULL OR `description` = '');
UPDATE `#__jem_special_days` SET `show_dates` = 0 WHERE `alias` = 'weekend' AND `day_type` = 'Weekend' AND `weekdays` IN ('0,6', '6,0');
ALTER TABLE `#__jem_types` MODIFY `entity` TINYINT(1) NOT NULL DEFAULT 1 COMMENT '1=Event, 2=Category, 3=Venue, 4=Day';
UPDATE `#__jem_special_days` AS sd INNER JOIN `#__jem_types` AS t ON t.entity = 4 AND t.name = sd.day_type SET sd.day_type_id = t.id WHERE sd.day_type_id = 0;
UPDATE `#__jem_venues` SET `attribs` = '{}' WHERE `attribs` IS NULL OR `attribs` = '' OR `attribs` = '""' OR `attribs` = "''" OR NOT JSON_VALID(`attribs`);
UPDATE `#__jem_events` SET `attribs` = '{}' WHERE `attribs` IS NULL OR `attribs` = '' OR `attribs` = '""' OR `attribs` = "''" OR NOT JSON_VALID(`attribs`);
UPDATE `#__jem_categories` SET `metadata` = '{}' WHERE `metadata` IS NULL OR `metadata` = '' OR `metadata` = '""' OR `metadata` = "''" OR NOT JSON_VALID(`metadata`);
UPDATE `#__jem_categories` SET `path` = NULL WHERE `id` = 1 AND `catname` = 'root' AND `path` IS NOT NULL;
UPDATE `#__jem_config` SET `value` = 'annualcalendar,attendeeregistrations,calendar,categories,category,day,event,eventslist,eventsmap,myattendances,myevents,mytimeline,myvenues,specialdays,typeevents,typevenues,venue,venues,venueslist,venuesmap,weekcal' WHERE `keyname` = 'pdf_enabled_views' AND `value` = 'event,annualcalendar';
UPDATE `#__jem_config` SET `value` = CONCAT(`value`, ',categories') WHERE `keyname` = 'pdf_enabled_views' AND FIND_IN_SET('categories', `value`) = 0;
UPDATE `#__jem_config` SET `value` = CONCAT(`value`, ',typevenues') WHERE `keyname` = 'pdf_enabled_views' AND FIND_IN_SET('typevenues', `value`) = 0;
UPDATE `#__jem_config` SET `value` = CONCAT(`value`, ',venues') WHERE `keyname` = 'pdf_enabled_views' AND FIND_IN_SET('venues', `value`) = 0;

